function isoTimestamp(clock) {
  const value = clock();
  const date = value instanceof Date ? value : new Date(value);
  return date.toISOString();
}

function identifyRoute(pathname, method) {
  if (pathname === '/notes') {
    if (method === 'POST') return { operation: 'create' };
    if (method === 'GET') return { operation: 'list' };
    throw errors.methodNotAllowed(['GET', 'POST']);
  }

  const match = /^\/notes\/([^/]+)$/.exec(pathname);
  if (!match) throw errors.routeNotFound();
  if (method === 'GET') return { operation: 'read', noteId: match[1] };
  if (method === 'PATCH') return { operation: 'update', noteId: match[1] };
  if (method === 'DELETE') return { operation: 'delete', noteId: match[1] };
  throw errors.methodNotAllowed(['GET', 'PATCH', 'DELETE']);
}

export function createApp({
  store,
  clock = () => new Date(),
  idFactory,
  logger = console
}) {
  if (!store) throw new TypeError('store is required');
  if (!idFactory) throw new TypeError('idFactory is required');

  return async function app(request, response) {
    try {
      const url = new URL(request.url, 'http://localhost');
      const route = identifyRoute(url.pathname, request.method);
      const user = authenticate(request, store);
      if (!user) throw errors.unauthenticated();

      if (route.noteId) {
        const issues = validateNoteId(route.noteId);
        if (issues.length > 0) throw errors.validation(issues);
      }

      if (route.operation === 'create') {
        const validation = validateCreateNote(await readJson(request));
        if (validation.issues.length > 0) {
          throw errors.validation(validation.issues);
        }
        const note = store.createNote({
          id: idFactory(),
          ...validation.value,
          ownerId: user.id,
          organizationId: user.organizationId,
          now: isoTimestamp(clock)
        });
        json(response, 201, note, { Location: `/notes/${note.id}` });
        return;
      }

      if (route.operation === 'list') {
        json(response, 200, {
          notes: store.listNotesForOrganization(user.organizationId)
        });
        return;
      }

      if (route.operation === 'read') {
        const note = store.getNoteForOrganization(
          route.noteId,
          user.organizationId
        );
        if (!note) throw errors.noteNotFound();
        json(response, 200, note);
        return;
      }

      if (route.operation === 'update') {
        const validation = validateUpdateNote(await readJson(request));
        if (validation.issues.length > 0) {
          throw errors.validation(validation.issues);
        }
        const note = store.updateNoteForOrganization(
          route.noteId,
          user.organizationId,
          validation.value,
          isoTimestamp(clock)
        );
        if (!note) throw errors.noteNotFound();
        json(response, 200, note);
        return;
      }

      const deleted = store.deleteNoteForOrganization(
        route.noteId,
        user.organizationId
      );
      if (!deleted) throw errors.noteNotFound();
      response.writeHead(204);
      response.end();
    } catch (error) {
      if (error instanceof HttpError) {
        sendError(response, error);
        return;
      }
      logger.error('Unexpected request error', error);
      sendError(
        response,
        new HttpError(500, 'INTERNAL_ERROR', 'Internal server error')
      );
    }
  };
}
import { createHash } from 'node:crypto';

export function hashToken(token) {
  return createHash('sha256').update(token, 'utf8').digest('hex');
}

function authorizationValues(request) {
  const values = [];
  for (let index = 0; index < request.rawHeaders.length; index += 2) {
    if (request.rawHeaders[index].toLowerCase() === 'authorization') {
      values.push(request.rawHeaders[index + 1]);
    }
  }
  return values;
}

export function authenticate(request, store) {
  const values = authorizationValues(request);
  if (values.length !== 1) return null;

  const match = /^Bearer ([^\s,]+)$/.exec(values[0]);
  if (!match) return null;

  return store.findUserByTokenHash(hashToken(match[1]));
}
import { randomBytes } from 'node:crypto';
import { fileURLToPath } from 'node:url';
import { resolve } from 'node:path';
import { hashToken } from './auth.js';
import { openStore } from './store.js';

export const identityDefinitions = [
  { id: 'user-a1', organizationId: 'org-a', name: 'User A1', env: 'TOKEN_USER_A1' },
  { id: 'user-a2', organizationId: 'org-a', name: 'User A2', env: 'TOKEN_USER_A2' },
  { id: 'user-b1', organizationId: 'org-b', name: 'User B1', env: 'TOKEN_USER_B1' },
  { id: 'user-b2', organizationId: 'org-b', name: 'User B2', env: 'TOKEN_USER_B2' }
];

export function initialize({
  store,
  environment = process.env,
  generateToken = () => randomBytes(32).toString('base64url'),
  output = console.log
}) {
  const generated = [];
  const users = identityDefinitions.map((definition) => {
    const supplied = environment[definition.env];
    const token = supplied && supplied.length > 0 ? supplied : generateToken();
    if (!supplied) generated.push({ ...definition, token });
    return {
      id: definition.id,
      organizationId: definition.organizationId,
      name: definition.name,
      tokenHash: hashToken(token)
    };
  });

  const created = store.initializeIdentities({
    organizations: [
      { id: 'org-a', name: 'Organization A' },
      { id: 'org-b', name: 'Organization B' }
    ],
    users
  });

  if (created) {
    if (generated.length > 0) {
      output('Generated API tokens (shown only this once):');
      for (const user of generated) output(`${user.env}=${user.token}`);
    }
    output('Initialized 2 organizations and 4 users.');
  } else {
    output('Identity data is already initialized; no tokens were changed.');
  }
  return { created, generated };
}

function isMainModule() {
  return process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url);
}

if (isMainModule()) {
  const store = openStore(resolve(process.env.DATA_FILE ?? './data/notes.sqlite'));
  try {
    initialize({ store });
  } finally {
    store.close();
  }
}

import { mkdirSync } from 'node:fs';
import { dirname } from 'node:path';
import { DatabaseSync } from 'node:sqlite';

function mapNote(row) {
  if (!row) return null;
  return {
    id: row.id,
    title: row.title,
    body: row.body,
    ownerId: row.owner_id,
    organizationId: row.organization_id,
    createdAt: row.created_at,
    updatedAt: row.updated_at
  };
}

function migrate(database) {
  const version = database.prepare('PRAGMA user_version').get().user_version;
  if (version > 1) {
    throw new Error(`Database schema version ${version} is newer than this application supports`);
  }
  if (version === 1) return;

  database.exec('BEGIN IMMEDIATE');
  try {
    database.exec(`
      CREATE TABLE organizations (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL
      ) STRICT;

      CREATE TABLE users (
        id TEXT PRIMARY KEY,
        organization_id TEXT NOT NULL REFERENCES organizations(id),
        name TEXT NOT NULL,
        token_hash TEXT NOT NULL UNIQUE,
        UNIQUE (id, organization_id)
      ) STRICT;

      CREATE TABLE notes (
        id TEXT PRIMARY KEY,
        title TEXT NOT NULL,
        body TEXT NOT NULL,
        owner_id TEXT NOT NULL,
        organization_id TEXT NOT NULL,
        created_at TEXT NOT NULL,
        updated_at TEXT NOT NULL,
        FOREIGN KEY (owner_id, organization_id)
          REFERENCES users(id, organization_id)
      ) STRICT;

      CREATE INDEX notes_organization_order
        ON notes (organization_id, created_at DESC, id ASC);

      PRAGMA user_version = 1;
    `);
    database.exec('COMMIT');
  } catch (error) {
    database.exec('ROLLBACK');
    throw error;
  }
}

export function openStore(dataFile) {
  mkdirSync(dirname(dataFile), { recursive: true });
  const database = new DatabaseSync(dataFile);

  try {
    database.exec(`
      PRAGMA foreign_keys = ON;
      PRAGMA journal_mode = WAL;
      PRAGMA busy_timeout = 2000;
      PRAGMA synchronous = FULL;
    `);
    migrate(database);
  } catch (error) {
    database.close();
    throw error;
  }

  const statements = {
    identityCounts: database.prepare(`
      SELECT
        (SELECT COUNT(*) FROM organizations) AS organizations,
        (SELECT COUNT(*) FROM users) AS users
    `),
    insertOrganization: database.prepare(
      'INSERT INTO organizations (id, name) VALUES (?, ?)'
    ),
    insertUser: database.prepare(`
      INSERT INTO users (id, organization_id, name, token_hash)
      VALUES (?, ?, ?, ?)
    `),
    userByTokenHash: database.prepare(`
      SELECT id, organization_id AS organizationId, name
      FROM users
      WHERE token_hash = ?
    `),
    createNote: database.prepare(`
      INSERT INTO notes
        (id, title, body, owner_id, organization_id, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    `),
    listNotes: database.prepare(`
      SELECT *
      FROM notes
      WHERE organization_id = ?
      ORDER BY created_at DESC, id ASC
    `),
    getNote: database.prepare(`
      SELECT *
      FROM notes
      WHERE id = ? AND organization_id = ?
    `),
    updateTitle: database.prepare(`
      UPDATE notes
      SET title = ?, updated_at = ?
      WHERE id = ? AND organization_id = ?
    `),
    updateBody: database.prepare(`
      UPDATE notes
      SET body = ?, updated_at = ?
      WHERE id = ? AND organization_id = ?
    `),
    updateTitleAndBody: database.prepare(`
      UPDATE notes
      SET title = ?, body = ?, updated_at = ?
      WHERE id = ? AND organization_id = ?
    `),
    deleteNote: database.prepare(`
      DELETE FROM notes
      WHERE id = ? AND organization_id = ?
    `)
  };

  let closed = false;

  return {
    initializeIdentities({ organizations, users }) {
      const counts = statements.identityCounts.get();
      if (counts.organizations !== 0 || counts.users !== 0) {
        if (counts.organizations !== 2 || counts.users !== 4) {
          throw new Error(
            `Identity database must contain exactly 2 organizations and 4 users; found ${counts.organizations} and ${counts.users}`
          );
        }
        return false;
      }

      database.exec('BEGIN IMMEDIATE');
      try {
        for (const organization of organizations) {
          statements.insertOrganization.run(organization.id, organization.name);
        }
        for (const user of users) {
          statements.insertUser.run(
            user.id,
            user.organizationId,
            user.name,
            user.tokenHash
          );
        }
        database.exec('COMMIT');
        return true;
      } catch (error) {
        database.exec('ROLLBACK');
        throw error;
      }
    },

    findUserByTokenHash(tokenHash) {
      return statements.userByTokenHash.get(tokenHash) ?? null;
    },

    createNote({ id, title, body, ownerId, organizationId, now }) {
      statements.createNote.run(
        id,
        title,
        body,
        ownerId,
        organizationId,
        now,
        now
      );
      return mapNote(statements.getNote.get(id, organizationId));
    },

    listNotesForOrganization(organizationId) {
      return statements.listNotes.all(organizationId).map(mapNote);
    },

    getNoteForOrganization(noteId, organizationId) {
      return mapNote(statements.getNote.get(noteId, organizationId));
    },

    updateNoteForOrganization(noteId, organizationId, changes, now) {
      let result;
      if (changes.title !== undefined && changes.body !== undefined) {
        result = statements.updateTitleAndBody.run(
          changes.title,
          changes.body,
          now,
          noteId,
          organizationId
        );
      } else if (changes.title !== undefined) {
        result = statements.updateTitle.run(
          changes.title,
          now,
          noteId,
          organizationId
        );
      } else {
        result = statements.updateBody.run(
          changes.body,
          now,
          noteId,
          organizationId
        );
      }
      if (result.changes === 0) return null;
      return mapNote(statements.getNote.get(noteId, organizationId));
    },

    deleteNoteForOrganization(noteId, organizationId) {
      return statements.deleteNote.run(noteId, organizationId).changes > 0;
    },

    close() {
      if (!closed) {
        database.close();
        closed = true;
      }
    }
  };
}
